export declare const script = "\n(function () {\n\ndocument.querySelectorAll(\".pg-table\").forEach(initTable);\n\nfunction initTable(wrapper) {\n\n  const tbody = wrapper.querySelector(\"tbody\");\n  if (!tbody) return;\n\n  const rows = [...tbody.querySelectorAll(\"tr\")];\n\n  const search = wrapper.querySelector(\".table-search\");\n  const select = wrapper.querySelector(\".rows-select\");\n  const info = wrapper.querySelector(\".page-info\");\n  const pager = wrapper.querySelector(\".pagination\");\n  const headers = [...wrapper.querySelectorAll(\"thead th\")];\n\n  let page = 1;\n  let sortColumn = -1;\n  let ascending = true;\n\n  restorePageSize();\n\n  headers.forEach((th, index) => {\n\n    th.style.cursor = \"pointer\";\n    th.title = \"Sort\";\n\n    th.onclick = () => {\n\n      if (sortColumn === index) {\n        ascending = !ascending;\n      } else {\n        sortColumn = index;\n        ascending = true;\n      }\n\n      sortRows(index);\n      page = 1;\n      render();\n\n    };\n\n  });\n\n  function restorePageSize() {\n\n    const value = localStorage.getItem(\"pg-page-size\");\n\n    if (value) {\n      select.value = value;\n    }\n\n  }\n\n  function savePageSize() {\n\n    localStorage.setItem(\"pg-page-size\", select.value);\n\n  }\n\n  function size() {\n\n    const value = select.value;\n\n    return value === \"all\"\n      ? rows.length\n      : Number(value);\n\n  }\n\n  function sortRows(column) {\n\n    rows.sort((a, b) => {\n\n      const av = a.cells[column].innerText.trim().toLowerCase();\n      const bv = b.cells[column].innerText.trim().toLowerCase();\n\n      const result = av.localeCompare(\n        bv,\n        undefined,\n        { numeric: true }\n      );\n\n      return ascending ? result : -result;\n\n    });\n\n    rows.forEach(r => tbody.appendChild(r));\n\n  }\n\n  function highlight(row, q) {\n\n    [...row.cells].forEach(cell => {\n\n      const text = cell.textContent || \"\";\n\n      cell.innerHTML = text;\n\n      if (!q) return;\n\n      cell.innerHTML = text.split(q).join(\"<mark>\" + q + \"</mark>\");\n\n    });\n\n  }\n\n  function filtered() {\n\n    const q = (search.value || \"\").trim().toLowerCase();\n\n    return rows.filter(r => {\n\n      highlight(r, q);\n\n      return r.innerText.toLowerCase().includes(q);\n\n    });\n\n  }\n\n  function render() {\n\n    const visible = filtered();\n\n    const pageSize = size();\n\n    const pages = Math.max(\n      1,\n      Math.ceil(visible.length / pageSize)\n    );\n\n    page = Math.min(page, pages);\n\n    rows.forEach(r => {\n      r.style.display = \"none\";\n    });\n\n    const start = (page - 1) * pageSize;\n\n    const end = Math.min(\n      start + pageSize,\n      visible.length\n    );\n\n    visible\n      .slice(start, end)\n      .forEach(r => {\n\n        r.style.display = \"\";\n\n      });\n\n    info.textContent =\n      \"Showing \" +\n      (visible.length === 0 ? 0 : start + 1) +\n      \"-\" +\n      end +\n      \" of \" +\n      visible.length;\n\n    pager.innerHTML = \"\";\n\n    const prev = document.createElement(\"button\");\n\n    prev.textContent = \"\u25C0\";\n\n    prev.disabled = page === 1;\n\n    prev.onclick = () => {\n\n      page--;\n\n      render();\n\n    };\n\n    pager.appendChild(prev);\n\n    const maxButtons = 7;\n\n    let first = Math.max(1, page - 3);\n\n    let last = Math.min(\n      pages,\n      first + maxButtons - 1\n    );\n\n    first = Math.max(\n      1,\n      last - maxButtons + 1\n    );\n\n    for (let i = first; i <= last; i++) {\n\n      const b = document.createElement(\"button\");\n\n      b.textContent = i;\n\n      if (i === page) {\n        b.className = \"active\";\n      }\n\n      b.onclick = () => {\n\n        page = i;\n\n        render();\n\n      };\n\n      pager.appendChild(b);\n\n    }\n\n    const next = document.createElement(\"button\");\n\n    next.textContent = \"\u25B6\";\n\n    next.disabled = page === pages;\n\n    next.onclick = () => {\n\n      page++;\n\n      render();\n\n    };\n\n    pager.appendChild(next);\n\n  }\n\n  search.oninput = () => {\n\n    page = 1;\n\n    render();\n\n  };\n\n  select.onchange = () => {\n\n    savePageSize();\n\n    page = 1;\n\n    render();\n\n  };\n\n  render();\n\n}\n\n})();\n";
